diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..dfca715ae9b6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5669,8 +5669,59 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
   Pred = Pred.dropSameSign();
   auto CmpXZ = IsCondKnownTrue(simplifyICmpInst(Pred, X, Z, Q));
   auto CmpYZ = IsCondKnownTrue(simplifyICmpInst(Pred, Y, Z, Q));
-  if (!CmpXZ.has_value() && !CmpYZ.has_value())
+  if (!CmpXZ.has_value() && !CmpYZ.has_value()) {
+    // Try to recognize clamp pattern:
+    // icmp eq/ne Z, smin(smax(Z, LowC), HighC)
+    // icmp eq/ne Z, smax(smin(Z, HighC), LowC)
+    // This checks if Z is within [LowC, HighC], which can be done with an
+    // unsigned comparison: icmp ule (Z - LowC), (HighC - LowC)
+    if (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE) {
+      const APInt *LowC = nullptr, *HighC = nullptr;
+      auto MatchClamp = [&](Value *Inner, Value *OuterC) -> bool {
+        const APInt *OuterVal;
+        if (!match(OuterC, m_APInt(OuterVal)))
+          return false;
+        Intrinsic::ID OuterID = MinMax->getIntrinsicID();
+        if (OuterID == Intrinsic::smin) {
+          // smin(inner, HighC) where inner is smax(Z, LowC)
+          if (match(Inner, m_OneUse(m_c_SMax(m_Specific(Z), m_APInt(LowC))))) {
+            HighC = OuterVal;
+            return true;
+          }
+        } else if (OuterID == Intrinsic::smax) {
+          // smax(inner, LowC) where inner is smin(Z, HighC)
+          if (match(Inner, m_OneUse(m_c_SMin(m_Specific(Z), m_APInt(HighC))))) {
+            LowC = OuterVal;
+            return true;
+          }
+        } else if (OuterID == Intrinsic::umin) {
+          if (match(Inner, m_OneUse(m_c_UMax(m_Specific(Z), m_APInt(LowC))))) {
+            HighC = OuterVal;
+            return true;
+          }
+        } else if (OuterID == Intrinsic::umax) {
+          if (match(Inner, m_OneUse(m_c_UMin(m_Specific(Z), m_APInt(HighC))))) {
+            LowC = OuterVal;
+            return true;
+          }
+        }
+        return false;
+      };
+      bool IsClamp = MatchClamp(X, Y) || MatchClamp(Y, X);
+      if (IsClamp && LowC->slt(*HighC)) {
+        // Z in [LowC, HighC] iff (Z - LowC) <=u (HighC - LowC)
+        Value *Sub =
+            Builder.CreateSub(Z, ConstantInt::get(Z->getType(), *LowC));
+        APInt Range = *HighC - *LowC;
+        ICmpInst::Predicate NewPred = (Pred == ICmpInst::ICMP_EQ)
+                                          ? ICmpInst::ICMP_ULE
+                                          : ICmpInst::ICMP_UGT;
+        return new ICmpInst(NewPred, Sub,
+                            ConstantInt::get(Z->getType(), Range));
+      }
+    }
     return nullptr;
+  }
   if (!CmpXZ.has_value()) {
     std::swap(X, Y);
     std::swap(CmpXZ, CmpYZ);

